#include <stdio.h>
#include <string.h>
#include <openssl/sha.h>

// Structure to represent a node in the Merkle tree
typedef struct Node {
 unsigned char hash[SHA256_DIGEST_LENGTH];
 struct Node* left;
 struct Node* right;
} Node;

// Function to create a new node
Node* createNode(unsigned char* data) {
 Node* node = malloc(sizeof(Node));
 SHA256(data, strlen((char*)data), node->hash);
 node->left = NULL;
 node->right = NULL;
 return node;
}

// Function to build the Merkle tree
Node* buildMerkleTree(unsigned char** data, int size) {
 if (size == 1) {
 return createNode(data[0]);
 }
 Node* left = buildMerkleTree(data, size / 2);
 Node* right = buildMerkleTree(data + size / 2, size / 2);
 Node* node = malloc(sizeof(Node));
 unsigned char combined[SHA256_DIGEST_LENGTH * 2];
 memcpy(combined, left->hash, SHA256_DIGEST_LENGTH);
 memcpy(combined + SHA256_DIGEST_LENGTH, right->hash, SHA256_DIGEST_LENGTH);
 SHA256(combined, SHA256_DIGEST_LENGTH * 2, node->hash);
 node->left = left;
 node->right = right;
 return node;
}
